// SAT Math Batch 10 - Data Analysis & Statistics II (120 questions)
export const mathBatch10 = [
  { id: 'sat_math_b10_001', category: 'math', subcategory: 'data-analysis', difficulty: 'easy', passage: null, question: 'A data set contains the values 3, 7, 7, 9, and 14. What is the mean of this data set?', options: [{ letter: 'A', text: '8' }, { letter: 'B', text: '7' }, { letter: 'C', text: '9' }, { letter: 'D', text: '10' }], correct: 'A', explanation: 'The mean is (3 + 7 + 7 + 9 + 14) / 5 = 40 / 5 = 8.' },
  { id: 'sat_math_b10_002', category: 'math', subcategory: 'data-analysis', difficulty: 'easy', passage: null, question: 'What is the median of the data set {2, 5, 8, 11, 14}?', options: [{ letter: 'A', text: '8' }, { letter: 'B', text: '5' }, { letter: 'C', text: '11' }, { letter: 'D', text: '7' }], correct: 'A', explanation: 'With five values in order, the median is the third value, which is 8.' },
  { id: 'sat_math_b10_003', category: 'math', subcategory: 'data-analysis', difficulty: 'easy', passage: null, question: 'What is the mode of the data set {4, 6, 6, 8, 10, 12}?', options: [{ letter: 'A', text: '6' }, { letter: 'B', text: '8' }, { letter: 'C', text: '7' }, { letter: 'D', text: '10' }], correct: 'A', explanation: 'The mode is the value that appears most frequently. The value 6 appears twice while all others appear once.' },
  { id: 'sat_math_b10_004', category: 'math', subcategory: 'data-analysis', difficulty: 'easy', passage: null, question: 'What is the range of the data set {3, 8, 15, 22, 27}?', options: [{ letter: 'A', text: '24' }, { letter: 'B', text: '22' }, { letter: 'C', text: '19' }, { letter: 'D', text: '15' }], correct: 'A', explanation: 'The range is the maximum minus the minimum: 27 − 3 = 24.' },
  { id: 'sat_math_b10_005', category: 'math', subcategory: 'data-analysis', difficulty: 'easy', passage: null, question: 'A bag contains 3 red marbles, 5 blue marbles, and 2 green marbles. What is the probability of randomly selecting a blue marble?', options: [{ letter: 'A', text: '1/2' }, { letter: 'B', text: '3/10' }, { letter: 'C', text: '2/5' }, { letter: 'D', text: '1/5' }], correct: 'A', explanation: 'There are 5 blue marbles out of 10 total, so the probability is 5/10 = 1/2.' },
  { id: 'sat_math_b10_006', category: 'math', subcategory: 'data-analysis', difficulty: 'easy', passage: null, question: 'The test scores for 6 students are 70, 75, 80, 85, 90, and 100. What is the mean score?', options: [{ letter: 'A', text: '83.33' }, { letter: 'B', text: '82.50' }, { letter: 'C', text: '85' }, { letter: 'D', text: '80' }], correct: 'A', explanation: 'The mean is (70 + 75 + 80 + 85 + 90 + 100) / 6 = 500 / 6 ≈ 83.33.' },
  { id: 'sat_math_b10_007', category: 'math', subcategory: 'data-analysis', difficulty: 'easy', passage: null, question: 'A coin is flipped twice. What is the probability of getting heads on both flips?', options: [{ letter: 'A', text: '1/4' }, { letter: 'B', text: '1/2' }, { letter: 'C', text: '3/4' }, { letter: 'D', text: '1/3' }], correct: 'A', explanation: 'Each flip has probability 1/2 of heads, so both heads is (1/2)(1/2) = 1/4.' },
  { id: 'sat_math_b10_008', category: 'math', subcategory: 'data-analysis', difficulty: 'easy', passage: null, question: 'What is the median of the data set {1, 3, 5, 7, 9, 11}?', options: [{ letter: 'A', text: '6' }, { letter: 'B', text: '5' }, { letter: 'C', text: '7' }, { letter: 'D', text: '5.5' }], correct: 'A', explanation: 'With an even number of values, the median is the average of the two middle values: (5 + 7) / 2 = 6.' },
  { id: 'sat_math_b10_009', category: 'math', subcategory: 'data-analysis', difficulty: 'easy', passage: null, question: 'A class has 12 boys and 18 girls. What is the probability that a randomly selected student is a boy?', options: [{ letter: 'A', text: '2/5' }, { letter: 'B', text: '3/5' }, { letter: 'C', text: '1/2' }, { letter: 'D', text: '1/3' }], correct: 'A', explanation: 'There are 12 boys out of 30 total students, so the probability is 12/30 = 2/5.' },
  { id: 'sat_math_b10_010', category: 'math', subcategory: 'data-analysis', difficulty: 'easy', passage: null, question: 'The data set {10, 20, 30, 40, 50} has a mean of 30. If each value is increased by 5, what is the new mean?', options: [{ letter: 'A', text: '35' }, { letter: 'B', text: '30' }, { letter: 'C', text: '40' }, { letter: 'D', text: '25' }], correct: 'A', explanation: 'Adding a constant to every value increases the mean by that same constant: 30 + 5 = 35.' },
  { id: 'sat_math_b10_011', category: 'math', subcategory: 'data-analysis', difficulty: 'easy', passage: null, question: 'A standard deck of 52 cards contains 4 aces. What is the probability of drawing an ace at random?', options: [{ letter: 'A', text: '1/13' }, { letter: 'B', text: '1/52' }, { letter: 'C', text: '1/4' }, { letter: 'D', text: '4/13' }], correct: 'A', explanation: 'The probability is 4/52 = 1/13.' },
  { id: 'sat_math_b10_012', category: 'math', subcategory: 'data-analysis', difficulty: 'easy', passage: null, question: 'What is the interquartile range (IQR) of the data set {2, 4, 6, 8, 10, 12, 14, 16}?', options: [{ letter: 'A', text: '8' }, { letter: 'B', text: '6' }, { letter: 'C', text: '10' }, { letter: 'D', text: '4' }], correct: 'A', explanation: 'Q1 is the median of {2, 4, 6, 8} = 5, and Q3 is the median of {10, 12, 14, 16} = 13. IQR = 13 − 5 = 8.' },
  { id: 'sat_math_b10_013', category: 'math', subcategory: 'data-analysis', difficulty: 'easy', passage: null, question: 'A spinner has 4 equal sections colored red, blue, green, and yellow. What is the probability of landing on red or blue?', options: [{ letter: 'A', text: '1/2' }, { letter: 'B', text: '1/4' }, { letter: 'C', text: '3/4' }, { letter: 'D', text: '1/3' }], correct: 'A', explanation: 'Two favorable outcomes out of four: 2/4 = 1/2.' },
  { id: 'sat_math_b10_014', category: 'math', subcategory: 'data-analysis', difficulty: 'easy', passage: null, question: 'The mean of five numbers is 20. What is the sum of the five numbers?', options: [{ letter: 'A', text: '100' }, { letter: 'B', text: '80' }, { letter: 'C', text: '25' }, { letter: 'D', text: '50' }], correct: 'A', explanation: 'Mean = sum / count, so sum = mean × count = 20 × 5 = 100.' },
  { id: 'sat_math_b10_015', category: 'math', subcategory: 'data-analysis', difficulty: 'easy', passage: null, question: 'In a survey of 200 people, 60 preferred chocolate ice cream. What percentage preferred chocolate?', options: [{ letter: 'A', text: '30%' }, { letter: 'B', text: '25%' }, { letter: 'C', text: '35%' }, { letter: 'D', text: '40%' }], correct: 'A', explanation: '60/200 = 0.30 = 30%.' },
  { id: 'sat_math_b10_016', category: 'math', subcategory: 'data-analysis', difficulty: 'easy', passage: null, question: 'A die is rolled once. What is the probability of rolling a number greater than 4?', options: [{ letter: 'A', text: '1/3' }, { letter: 'B', text: '1/2' }, { letter: 'C', text: '2/3' }, { letter: 'D', text: '1/6' }], correct: 'A', explanation: 'Numbers greater than 4 are 5 and 6, giving 2 favorable outcomes out of 6: 2/6 = 1/3.' },
  { id: 'sat_math_b10_017', category: 'math', subcategory: 'data-analysis', difficulty: 'easy', passage: null, question: 'The data set {4, 4, 5, 6, 7, 7, 7, 9} has which mode?', options: [{ letter: 'A', text: '7' }, { letter: 'B', text: '4' }, { letter: 'C', text: '5.5' }, { letter: 'D', text: '6' }], correct: 'A', explanation: 'The value 7 appears three times, more than any other value.' },
  { id: 'sat_math_b10_018', category: 'math', subcategory: 'data-analysis', difficulty: 'easy', passage: null, question: 'If the mean of 10, 15, 20, and x is 17.5, what is the value of x?', options: [{ letter: 'A', text: '25' }, { letter: 'B', text: '20' }, { letter: 'C', text: '30' }, { letter: 'D', text: '22' }], correct: 'A', explanation: 'Mean × count = sum, so 17.5 × 4 = 70. Then x = 70 − (10 + 15 + 20) = 70 − 45 = 25.' },
  { id: 'sat_math_b10_019', category: 'math', subcategory: 'data-analysis', difficulty: 'easy', passage: null, question: 'A box plot shows Q1 = 20 and Q3 = 36. What is the interquartile range?', options: [{ letter: 'A', text: '16' }, { letter: 'B', text: '28' }, { letter: 'C', text: '56' }, { letter: 'D', text: '8' }], correct: 'A', explanation: 'IQR = Q3 − Q1 = 36 − 20 = 16.' },
  { id: 'sat_math_b10_020', category: 'math', subcategory: 'data-analysis', difficulty: 'easy', passage: null, question: 'In a two-way table, 40 students take math, 30 take science, and 15 take both. How many take math or science?', options: [{ letter: 'A', text: '55' }, { letter: 'B', text: '70' }, { letter: 'C', text: '45' }, { letter: 'D', text: '85' }], correct: 'A', explanation: 'By the inclusion-exclusion principle: 40 + 30 − 15 = 55.' },
  { id: 'sat_math_b10_021', category: 'math', subcategory: 'data-analysis', difficulty: 'easy', passage: null, question: 'A data set has values {1, 2, 3, 4, 5}. If each value is doubled, what is the new mean?', options: [{ letter: 'A', text: '6' }, { letter: 'B', text: '3' }, { letter: 'C', text: '5' }, { letter: 'D', text: '10' }], correct: 'A', explanation: 'The original mean is 3. Doubling every value doubles the mean: 3 × 2 = 6.' },
  { id: 'sat_math_b10_022', category: 'math', subcategory: 'data-analysis', difficulty: 'easy', passage: null, question: 'Two dice are rolled. How many total outcomes are in the sample space?', options: [{ letter: 'A', text: '36' }, { letter: 'B', text: '12' }, { letter: 'C', text: '6' }, { letter: 'D', text: '24' }], correct: 'A', explanation: 'Each die has 6 outcomes, so the total sample space is 6 × 6 = 36.' },
  { id: 'sat_math_b10_023', category: 'math', subcategory: 'data-analysis', difficulty: 'easy', passage: null, question: 'A student scored 80, 85, 90, and 95 on four tests. What score is needed on a fifth test to have an overall mean of 90?', options: [{ letter: 'A', text: '100' }, { letter: 'B', text: '95' }, { letter: 'C', text: '92' }, { letter: 'D', text: '88' }], correct: 'A', explanation: 'Required sum = 90 × 5 = 450. Current sum = 350. Fifth score = 450 − 350 = 100.' },
  { id: 'sat_math_b10_024', category: 'math', subcategory: 'data-analysis', difficulty: 'easy', passage: null, question: 'What is the probability of NOT rolling a 6 on a single die?', options: [{ letter: 'A', text: '5/6' }, { letter: 'B', text: '1/6' }, { letter: 'C', text: '4/6' }, { letter: 'D', text: '1/3' }], correct: 'A', explanation: 'P(not 6) = 1 − P(6) = 1 − 1/6 = 5/6.' },
  { id: 'sat_math_b10_025', category: 'math', subcategory: 'data-analysis', difficulty: 'easy', passage: null, question: 'The median of 11 data values arranged in order is the value in which position?', options: [{ letter: 'A', text: '6th' }, { letter: 'B', text: '5th' }, { letter: 'C', text: '7th' }, { letter: 'D', text: '11th' }], correct: 'A', explanation: 'For n values, the median is at position (n + 1)/2 = (11 + 1)/2 = 6th.' },
  { id: 'sat_math_b10_026', category: 'math', subcategory: 'data-analysis', difficulty: 'easy', passage: null, question: 'A survey found that 45 out of 150 respondents prefer brand X. What fraction of respondents prefer brand X?', options: [{ letter: 'A', text: '3/10' }, { letter: 'B', text: '1/3' }, { letter: 'C', text: '2/5' }, { letter: 'D', text: '1/4' }], correct: 'A', explanation: '45/150 = 3/10.' },
  { id: 'sat_math_b10_027', category: 'math', subcategory: 'data-analysis', difficulty: 'easy', passage: null, question: 'If the probability of rain on any given day is 0.3, what is the probability it does not rain?', options: [{ letter: 'A', text: '0.7' }, { letter: 'B', text: '0.3' }, { letter: 'C', text: '0.5' }, { letter: 'D', text: '0.6' }], correct: 'A', explanation: 'P(no rain) = 1 − 0.3 = 0.7.' },
  { id: 'sat_math_b10_028', category: 'math', subcategory: 'data-analysis', difficulty: 'easy', passage: null, question: 'The weights (in pounds) of 5 packages are 12, 15, 18, 21, and 24. What is the mean weight?', options: [{ letter: 'A', text: '18' }, { letter: 'B', text: '15' }, { letter: 'C', text: '21' }, { letter: 'D', text: '20' }], correct: 'A', explanation: 'Mean = (12 + 15 + 18 + 21 + 24) / 5 = 90 / 5 = 18.' },
  { id: 'sat_math_b10_029', category: 'math', subcategory: 'data-analysis', difficulty: 'easy', passage: null, question: 'In a group of 50 students, 20 play soccer and 15 play basketball. If 5 play both, how many play neither?', options: [{ letter: 'A', text: '20' }, { letter: 'B', text: '15' }, { letter: 'C', text: '10' }, { letter: 'D', text: '25' }], correct: 'A', explanation: 'Students playing at least one sport: 20 + 15 − 5 = 30. Neither: 50 − 30 = 20.' },
  { id: 'sat_math_b10_030', category: 'math', subcategory: 'data-analysis', difficulty: 'easy', passage: null, question: 'A scatter plot shows a strong positive correlation between hours studied and test scores. Which best describes the relationship?', options: [{ letter: 'A', text: 'As hours studied increases, test scores tend to increase.' }, { letter: 'B', text: 'As hours studied increases, test scores tend to decrease.' }, { letter: 'C', text: 'There is no relationship between the variables.' }, { letter: 'D', text: 'The variables are inversely related.' }], correct: 'A', explanation: 'A positive correlation means both variables tend to increase together.' },
  { id: 'sat_math_b10_031', category: 'math', subcategory: 'data-analysis', difficulty: 'easy', passage: null, question: 'The values 5, 10, 15, 20, 25, 30, and 35 have a median of what?', options: [{ letter: 'A', text: '20' }, { letter: 'B', text: '15' }, { letter: 'C', text: '25' }, { letter: 'D', text: '17.5' }], correct: 'A', explanation: 'With 7 values, the median is the 4th value: 20.' },
  { id: 'sat_math_b10_032', category: 'math', subcategory: 'data-analysis', difficulty: 'easy', passage: null, question: 'A jar has 8 red, 6 blue, and 6 yellow candies. What is the probability of picking a red candy?', options: [{ letter: 'A', text: '2/5' }, { letter: 'B', text: '3/10' }, { letter: 'C', text: '1/2' }, { letter: 'D', text: '4/10' }], correct: 'A', explanation: 'Total candies = 20. P(red) = 8/20 = 2/5.' },
  { id: 'sat_math_b10_033', category: 'math', subcategory: 'data-analysis', difficulty: 'easy', passage: null, question: 'The mean of three consecutive even numbers is 24. What is the largest number?', options: [{ letter: 'A', text: '26' }, { letter: 'B', text: '24' }, { letter: 'C', text: '28' }, { letter: 'D', text: '22' }], correct: 'A', explanation: 'If the mean is 24, the numbers are 22, 24, 26. The largest is 26.' },
  { id: 'sat_math_b10_034', category: 'math', subcategory: 'data-analysis', difficulty: 'easy', passage: null, question: 'A line of best fit has the equation y = 2x + 10. What is the predicted value of y when x = 5?', options: [{ letter: 'A', text: '20' }, { letter: 'B', text: '15' }, { letter: 'C', text: '25' }, { letter: 'D', text: '12' }], correct: 'A', explanation: 'y = 2(5) + 10 = 10 + 10 = 20.' },
  { id: 'sat_math_b10_035', category: 'math', subcategory: 'data-analysis', difficulty: 'easy', passage: null, question: 'If an event has a probability of 0, what does this mean?', options: [{ letter: 'A', text: 'The event is impossible.' }, { letter: 'B', text: 'The event is certain.' }, { letter: 'C', text: 'The event is unlikely.' }, { letter: 'D', text: 'The event has a 50% chance.' }], correct: 'A', explanation: 'A probability of 0 means the event cannot occur.' },
  { id: 'sat_math_b10_036', category: 'math', subcategory: 'data-analysis', difficulty: 'easy', passage: null, question: 'A data set has 5 values with a sum of 75. What is the mean?', options: [{ letter: 'A', text: '15' }, { letter: 'B', text: '25' }, { letter: 'C', text: '20' }, { letter: 'D', text: '12.5' }], correct: 'A', explanation: 'Mean = sum / count = 75 / 5 = 15.' },
  { id: 'sat_math_b10_037', category: 'math', subcategory: 'data-analysis', difficulty: 'easy', passage: null, question: 'In a frequency table, the value 8 appears 5 times and the value 12 appears 3 times. If these are the only values, what is the mean?', options: [{ letter: 'A', text: '9.5' }, { letter: 'B', text: '10' }, { letter: 'C', text: '8' }, { letter: 'D', text: '12' }], correct: 'A', explanation: 'Mean = (8×5 + 12×3) / (5 + 3) = (40 + 36) / 8 = 76 / 8 = 9.5.' },
  { id: 'sat_math_b10_038', category: 'math', subcategory: 'data-analysis', difficulty: 'easy', passage: null, question: 'A researcher surveys every 10th person entering a store. What type of sampling method is this?', options: [{ letter: 'A', text: 'Systematic sampling' }, { letter: 'B', text: 'Stratified sampling' }, { letter: 'C', text: 'Cluster sampling' }, { letter: 'D', text: 'Convenience sampling' }], correct: 'A', explanation: 'Selecting every kth individual from a population is systematic sampling.' },
  { id: 'sat_math_b10_039', category: 'math', subcategory: 'data-analysis', difficulty: 'easy', passage: null, question: 'The range of a data set is 18 and the minimum value is 7. What is the maximum value?', options: [{ letter: 'A', text: '25' }, { letter: 'B', text: '11' }, { letter: 'C', text: '18' }, { letter: 'D', text: '32' }], correct: 'A', explanation: 'Range = max − min, so max = range + min = 18 + 7 = 25.' },
  { id: 'sat_math_b10_040', category: 'math', subcategory: 'data-analysis', difficulty: 'easy', passage: null, question: 'In a two-way table, 25 males prefer tea and 35 males prefer coffee. What fraction of males prefer tea?', options: [{ letter: 'A', text: '5/12' }, { letter: 'B', text: '7/12' }, { letter: 'C', text: '1/2' }, { letter: 'D', text: '5/7' }], correct: 'A', explanation: 'Total males = 25 + 35 = 60. Fraction preferring tea = 25/60 = 5/12.' },
  { id: 'sat_math_b10_041', category: 'math', subcategory: 'data-analysis', difficulty: 'medium', passage: null, question: 'The mean of a data set of 8 values is 45. If a ninth value of 63 is added, what is the new mean?', options: [{ letter: 'A', text: '47' }, { letter: 'B', text: '48' }, { letter: 'C', text: '46' }, { letter: 'D', text: '54' }], correct: 'A', explanation: 'Original sum = 45 × 8 = 360. New sum = 360 + 63 = 423. New mean = 423 / 9 = 47.' },
  { id: 'sat_math_b10_042', category: 'math', subcategory: 'data-analysis', difficulty: 'medium', passage: null, question: 'The standard deviation of {10, 10, 10, 10, 10} is what?', options: [{ letter: 'A', text: '0' }, { letter: 'B', text: '10' }, { letter: 'C', text: '1' }, { letter: 'D', text: '5' }], correct: 'A', explanation: 'When all values are identical, there is no variation, so the standard deviation is 0.' },
  { id: 'sat_math_b10_043', category: 'math', subcategory: 'data-analysis', difficulty: 'medium', passage: null, question: 'A data set has Q1 = 15, Q2 = 22, and Q3 = 31. Using the 1.5×IQR rule, what is the upper fence for outliers?', options: [{ letter: 'A', text: '55' }, { letter: 'B', text: '46' }, { letter: 'C', text: '47' }, { letter: 'D', text: '52' }], correct: 'A', explanation: 'IQR = 31 − 15 = 16. Upper fence = Q3 + 1.5 × IQR = 31 + 24 = 55.' },
  { id: 'sat_math_b10_044', category: 'math', subcategory: 'data-analysis', difficulty: 'medium', passage: null, question: 'A scatter plot of data has a line of best fit y = −3x + 50. What does the slope indicate?', options: [{ letter: 'A', text: 'For each unit increase in x, y decreases by 3.' }, { letter: 'B', text: 'For each unit increase in x, y increases by 3.' }, { letter: 'C', text: 'The y-intercept is −3.' }, { letter: 'D', text: 'The correlation is positive.' }], correct: 'A', explanation: 'A slope of −3 means y decreases by 3 for every 1-unit increase in x.' },
  { id: 'sat_math_b10_045', category: 'math', subcategory: 'data-analysis', difficulty: 'medium', passage: null, question: 'In a normal distribution, approximately what percentage of data falls within one standard deviation of the mean?', options: [{ letter: 'A', text: '68%' }, { letter: 'B', text: '95%' }, { letter: 'C', text: '99.7%' }, { letter: 'D', text: '50%' }], correct: 'A', explanation: 'The empirical rule states that approximately 68% of data falls within one standard deviation of the mean.' },
  { id: 'sat_math_b10_046', category: 'math', subcategory: 'data-analysis', difficulty: 'medium', passage: null, question: 'A survey of 500 people has a margin of error of ±4%. If 60% support a proposal, what is the range of likely support in the population?', options: [{ letter: 'A', text: '56% to 64%' }, { letter: 'B', text: '54% to 66%' }, { letter: 'C', text: '58% to 62%' }, { letter: 'D', text: '52% to 68%' }], correct: 'A', explanation: 'The interval is 60% ± 4%, which gives 56% to 64%.' },
  { id: 'sat_math_b10_047', category: 'math', subcategory: 'data-analysis', difficulty: 'medium', passage: null, question: 'How many ways can 3 books be arranged on a shelf from a collection of 5 books?', options: [{ letter: 'A', text: '60' }, { letter: 'B', text: '10' }, { letter: 'C', text: '15' }, { letter: 'D', text: '120' }], correct: 'A', explanation: 'This is a permutation: P(5,3) = 5!/(5−3)! = 5 × 4 × 3 = 60.' },
  { id: 'sat_math_b10_048', category: 'math', subcategory: 'data-analysis', difficulty: 'medium', passage: null, question: 'A two-way table shows that 30 out of 80 seniors and 20 out of 120 juniors passed an AP exam. What is the probability that a randomly selected student who passed is a senior?', options: [{ letter: 'A', text: '3/5' }, { letter: 'B', text: '2/5' }, { letter: 'C', text: '3/8' }, { letter: 'D', text: '1/2' }], correct: 'A', explanation: 'Total who passed = 30 + 20 = 50. P(senior | passed) = 30/50 = 3/5.' },
  { id: 'sat_math_b10_049', category: 'math', subcategory: 'data-analysis', difficulty: 'medium', passage: null, question: 'A data set has a mean of 50 and a standard deviation of 5. What is the z-score of a value of 60?', options: [{ letter: 'A', text: '2' }, { letter: 'B', text: '10' }, { letter: 'C', text: '1' }, { letter: 'D', text: '−2' }], correct: 'A', explanation: 'z = (value − mean) / SD = (60 − 50) / 5 = 10 / 5 = 2.' },
  { id: 'sat_math_b10_050', category: 'math', subcategory: 'data-analysis', difficulty: 'medium', passage: null, question: 'In how many ways can a committee of 3 be chosen from 7 people?', options: [{ letter: 'A', text: '35' }, { letter: 'B', text: '21' }, { letter: 'C', text: '210' }, { letter: 'D', text: '120' }], correct: 'A', explanation: 'C(7,3) = 7! / (3! × 4!) = (7 × 6 × 5) / (3 × 2 × 1) = 35.' },
  { id: 'sat_math_b10_051', category: 'math', subcategory: 'data-analysis', difficulty: 'medium', passage: null, question: 'The expected value of a game is found by: winning $10 with probability 0.3 and losing $5 with probability 0.7. What is the expected value?', options: [{ letter: 'A', text: '-$0.50' }, { letter: 'B', text: '$1.50' }, { letter: 'C', text: '$3.00' }, { letter: 'D', text: '-$2.00' }], correct: 'A', explanation: 'E = (10)(0.3) + (−5)(0.7) = 3 − 3.50 = −$0.50.' },
  { id: 'sat_math_b10_052', category: 'math', subcategory: 'data-analysis', difficulty: 'medium', passage: null, question: 'A researcher wants to estimate the average height of students at a university. Which sampling method would introduce the least bias?', options: [{ letter: 'A', text: 'Simple random sample of all students' }, { letter: 'B', text: 'Survey only basketball players' }, { letter: 'C', text: 'Survey students in the cafeteria at lunch' }, { letter: 'D', text: 'Survey students in one dormitory' }], correct: 'A', explanation: 'A simple random sample gives every student an equal chance of being selected, minimizing bias.' },
  { id: 'sat_math_b10_053', category: 'math', subcategory: 'data-analysis', difficulty: 'medium', passage: null, question: 'The correlation coefficient r between two variables is −0.85. Which statement is true?', options: [{ letter: 'A', text: 'There is a strong negative linear relationship.' }, { letter: 'B', text: 'There is a weak negative linear relationship.' }, { letter: 'C', text: 'There is a strong positive linear relationship.' }, { letter: 'D', text: 'There is no linear relationship.' }], correct: 'A', explanation: 'An r value close to −1 indicates a strong negative linear relationship.' },
  { id: 'sat_math_b10_054', category: 'math', subcategory: 'data-analysis', difficulty: 'medium', passage: null, question: 'A normal distribution has a mean of 100 and a standard deviation of 15. What value is at the 84th percentile (one SD above the mean)?', options: [{ letter: 'A', text: '115' }, { letter: 'B', text: '130' }, { letter: 'C', text: '85' }, { letter: 'D', text: '110' }], correct: 'A', explanation: 'One standard deviation above the mean is 100 + 15 = 115, which corresponds to approximately the 84th percentile.' },
  { id: 'sat_math_b10_055', category: 'math', subcategory: 'data-analysis', difficulty: 'medium', passage: null, question: 'A box plot has a minimum of 10, Q1 = 20, median = 30, Q3 = 45, and maximum of 60. What is the IQR?', options: [{ letter: 'A', text: '25' }, { letter: 'B', text: '50' }, { letter: 'C', text: '30' }, { letter: 'D', text: '15' }], correct: 'A', explanation: 'IQR = Q3 − Q1 = 45 − 20 = 25.' },
  { id: 'sat_math_b10_056', category: 'math', subcategory: 'data-analysis', difficulty: 'medium', passage: null, question: 'A weighted average is calculated with scores of 80 (weight 2), 90 (weight 3), and 70 (weight 5). What is the weighted average?', options: [{ letter: 'A', text: '78' }, { letter: 'B', text: '80' }, { letter: 'C', text: '76' }, { letter: 'D', text: '82' }], correct: 'A', explanation: 'Weighted average = (80×2 + 90×3 + 70×5) / (2+3+5) = (160 + 270 + 350) / 10 = 780 / 10 = 78.' },
  { id: 'sat_math_b10_057', category: 'math', subcategory: 'data-analysis', difficulty: 'medium', passage: null, question: 'Two events A and B are independent. If P(A) = 0.4 and P(B) = 0.5, what is P(A and B)?', options: [{ letter: 'A', text: '0.2' }, { letter: 'B', text: '0.9' }, { letter: 'C', text: '0.1' }, { letter: 'D', text: '0.45' }], correct: 'A', explanation: 'For independent events, P(A and B) = P(A) × P(B) = 0.4 × 0.5 = 0.2.' },
  { id: 'sat_math_b10_058', category: 'math', subcategory: 'data-analysis', difficulty: 'medium', passage: null, question: 'The line of best fit for a data set is y = 1.5x + 3. What is the predicted y-value when x = 10?', options: [{ letter: 'A', text: '18' }, { letter: 'B', text: '15' }, { letter: 'C', text: '13' }, { letter: 'D', text: '20' }], correct: 'A', explanation: 'y = 1.5(10) + 3 = 15 + 3 = 18.' },
  { id: 'sat_math_b10_059', category: 'math', subcategory: 'data-analysis', difficulty: 'medium', passage: null, question: 'In a survey, 40% of respondents are male and 60% are female. Of males, 75% own a car; of females, 50% own a car. What is the overall probability of owning a car?', options: [{ letter: 'A', text: '0.60' }, { letter: 'B', text: '0.625' }, { letter: 'C', text: '0.55' }, { letter: 'D', text: '0.65' }], correct: 'A', explanation: 'P(car) = 0.40 × 0.75 + 0.60 × 0.50 = 0.30 + 0.30 = 0.60.' },
  { id: 'sat_math_b10_060', category: 'math', subcategory: 'data-analysis', difficulty: 'medium', passage: null, question: 'A data set of 20 values has a mean of 30. If the two largest values (both 50) are removed, what is the mean of the remaining 18 values?', options: [{ letter: 'A', text: '500/18' }, { letter: 'B', text: '25' }, { letter: 'C', text: '28' }, { letter: 'D', text: '26' }], correct: 'A', explanation: 'Original sum = 30 × 20 = 600. After removing two 50s: 600 − 100 = 500. New mean = 500/18 ≈ 27.78.' },
  { id: 'sat_math_b10_061', category: 'math', subcategory: 'data-analysis', difficulty: 'medium', passage: null, question: 'A population has a mean of 70 and standard deviation of 8. In a normal distribution, approximately what percentage of values fall between 54 and 86?', options: [{ letter: 'A', text: '95%' }, { letter: 'B', text: '68%' }, { letter: 'C', text: '99.7%' }, { letter: 'D', text: '50%' }], correct: 'A', explanation: '54 = 70 − 2(8) and 86 = 70 + 2(8), so this range is within two standard deviations, capturing about 95%.' },
  { id: 'sat_math_b10_062', category: 'math', subcategory: 'data-analysis', difficulty: 'medium', passage: null, question: 'A conditional probability P(A|B) = 0.6 and P(B) = 0.5. What is P(A and B)?', options: [{ letter: 'A', text: '0.3' }, { letter: 'B', text: '0.1' }, { letter: 'C', text: '1.1' }, { letter: 'D', text: '0.25' }], correct: 'A', explanation: 'P(A and B) = P(A|B) × P(B) = 0.6 × 0.5 = 0.3.' },
  { id: 'sat_math_b10_063', category: 'math', subcategory: 'data-analysis', difficulty: 'medium', passage: null, question: 'A histogram shows the following frequencies for test scores: 60-69 (5), 70-79 (12), 80-89 (18), 90-99 (15). How many students scored 80 or above?', options: [{ letter: 'A', text: '33' }, { letter: 'B', text: '18' }, { letter: 'C', text: '15' }, { letter: 'D', text: '35' }], correct: 'A', explanation: 'Students scoring 80 or above: 18 + 15 = 33.' },
  { id: 'sat_math_b10_064', category: 'math', subcategory: 'data-analysis', difficulty: 'medium', passage: null, question: 'How many different 4-letter arrangements can be made from the letters A, B, C, D, E with no repetition?', options: [{ letter: 'A', text: '120' }, { letter: 'B', text: '24' }, { letter: 'C', text: '60' }, { letter: 'D', text: '625' }], correct: 'A', explanation: 'P(5,4) = 5 × 4 × 3 × 2 = 120.' },
  { id: 'sat_math_b10_065', category: 'math', subcategory: 'data-analysis', difficulty: 'medium', passage: null, question: 'If the variance of a data set is 16, what is the standard deviation?', options: [{ letter: 'A', text: '4' }, { letter: 'B', text: '8' }, { letter: 'C', text: '256' }, { letter: 'D', text: '2' }], correct: 'A', explanation: 'Standard deviation is the square root of variance: √16 = 4.' },
  { id: 'sat_math_b10_066', category: 'math', subcategory: 'data-analysis', difficulty: 'medium', passage: null, question: 'A sample of 400 voters has a margin of error of ±5%. If 52% support a candidate, can you conclude the candidate has majority support?', options: [{ letter: 'A', text: 'No, because the interval 47% to 57% includes values below 50%.' }, { letter: 'B', text: 'Yes, because 52% is greater than 50%.' }, { letter: 'C', text: 'Yes, because the sample size is large enough.' }, { letter: 'D', text: 'No, because 400 is too small a sample.' }], correct: 'A', explanation: 'The confidence interval is 52% ± 5% = 47% to 57%, which includes values below 50%, so majority support cannot be concluded.' },
  { id: 'sat_math_b10_067', category: 'math', subcategory: 'data-analysis', difficulty: 'medium', passage: null, question: 'In a two-way table, 60 students study French, 45 study Spanish, and 200 students were surveyed. If 25 study both, how many study neither?', options: [{ letter: 'A', text: '120' }, { letter: 'B', text: '130' }, { letter: 'C', text: '95' }, { letter: 'D', text: '70' }], correct: 'A', explanation: 'At least one language: 60 + 45 − 25 = 80. Neither: 200 − 80 = 120.' },
  { id: 'sat_math_b10_068', category: 'math', subcategory: 'data-analysis', difficulty: 'medium', passage: null, question: 'A regression model predicts sales y (in thousands) based on advertising x (in hundreds). If y = 5x + 20 and the actual sales when x = 4 are 38 thousand, what is the residual?', options: [{ letter: 'A', text: '-2' }, { letter: 'B', text: '2' }, { letter: 'C', text: '38' }, { letter: 'D', text: '40' }], correct: 'A', explanation: 'Predicted y = 5(4) + 20 = 40. Residual = actual − predicted = 38 − 40 = −2.' },
  { id: 'sat_math_b10_069', category: 'math', subcategory: 'data-analysis', difficulty: 'medium', passage: null, question: 'A fair coin is flipped 3 times. What is the probability of getting exactly 2 heads?', options: [{ letter: 'A', text: '3/8' }, { letter: 'B', text: '1/4' }, { letter: 'C', text: '1/2' }, { letter: 'D', text: '1/8' }], correct: 'A', explanation: 'C(3,2) × (1/2)^2 × (1/2)^1 = 3 × 1/8 = 3/8.' },
  { id: 'sat_math_b10_070', category: 'math', subcategory: 'data-analysis', difficulty: 'medium', passage: null, question: 'The five-number summary of a data set is: min = 5, Q1 = 12, median = 18, Q3 = 24, max = 40. Using the 1.5×IQR rule, is 40 an outlier?', options: [{ letter: 'A', text: 'No, because 40 ≤ 42.' }, { letter: 'B', text: 'Yes, because 40 > 24.' }, { letter: 'C', text: 'Yes, because 40 > 30.' }, { letter: 'D', text: 'No, because 40 is the maximum.' }], correct: 'A', explanation: 'IQR = 24 − 12 = 12. Upper fence = 24 + 1.5(12) = 42. Since 40 ≤ 42, it is not an outlier.' },
  { id: 'sat_math_b10_071', category: 'math', subcategory: 'data-analysis', difficulty: 'medium', passage: null, question: 'A population doubles every 3 years. If the initial population is 500, what is the expected population after 9 years?', options: [{ letter: 'A', text: '4000' }, { letter: 'B', text: '2000' }, { letter: 'C', text: '1500' }, { letter: 'D', text: '8000' }], correct: 'A', explanation: 'In 9 years, the population doubles 3 times: 500 × 2³ = 500 × 8 = 4000.' },
  { id: 'sat_math_b10_072', category: 'math', subcategory: 'data-analysis', difficulty: 'medium', passage: null, question: 'A data set has values {2, 4, 6, 8, 10}. What is the population variance?', options: [{ letter: 'A', text: '8' }, { letter: 'B', text: '10' }, { letter: 'C', text: '4' }, { letter: 'D', text: '6' }], correct: 'A', explanation: 'Mean = 6. Variance = [(2−6)² + (4−6)² + (6−6)² + (8−6)² + (10−6)²] / 5 = (16+4+0+4+16)/5 = 40/5 = 8.' },
  { id: 'sat_math_b10_073', category: 'math', subcategory: 'data-analysis', difficulty: 'medium', passage: null, question: 'If the probability of event A is 0.35 and the probability of event B is 0.45, and A and B are mutually exclusive, what is P(A or B)?', options: [{ letter: 'A', text: '0.80' }, { letter: 'B', text: '0.1575' }, { letter: 'C', text: '0.45' }, { letter: 'D', text: '0.35' }], correct: 'A', explanation: 'For mutually exclusive events, P(A or B) = P(A) + P(B) = 0.35 + 0.45 = 0.80.' },
  { id: 'sat_math_b10_074', category: 'math', subcategory: 'data-analysis', difficulty: 'medium', passage: null, question: 'A study finds a correlation coefficient of r = 0.92 between hours of exercise per week and cardiovascular fitness score. Which conclusion is valid?', options: [{ letter: 'A', text: 'There is a strong positive association between the variables.' }, { letter: 'B', text: 'Exercise causes improved cardiovascular fitness.' }, { letter: 'C', text: 'The variables are not related.' }, { letter: 'D', text: 'There is a weak positive association.' }], correct: 'A', explanation: 'A high r value indicates strong association, but correlation does not imply causation.' },
  { id: 'sat_math_b10_075', category: 'math', subcategory: 'algebra', difficulty: 'medium', passage: null, question: 'A store sells an average of 120 items per day. If the standard deviation is 15 items, within what range do approximately 95% of daily sales fall?', options: [{ letter: 'A', text: '90 to 150' }, { letter: 'B', text: '105 to 135' }, { letter: 'C', text: '75 to 165' }, { letter: 'D', text: '100 to 140' }], correct: 'A', explanation: '95% falls within 2 standard deviations: 120 ± 2(15) = 120 ± 30, giving 90 to 150.' },
  { id: 'sat_math_b10_076', category: 'math', subcategory: 'data-analysis', difficulty: 'medium', passage: null, question: 'In a class of 30 students, 18 passed a math test and 20 passed a science test. If 12 passed both tests, what is the probability a randomly chosen student passed at least one test?', options: [{ letter: 'A', text: '13/15' }, { letter: 'B', text: '2/3' }, { letter: 'C', text: '4/5' }, { letter: 'D', text: '1' }], correct: 'A', explanation: 'At least one: 18 + 20 − 12 = 26. Probability = 26/30 = 13/15.' },
  { id: 'sat_math_b10_077', category: 'math', subcategory: 'data-analysis', difficulty: 'medium', passage: null, question: 'A z-score of −1.5 means a data point is:', options: [{ letter: 'A', text: '1.5 standard deviations below the mean' }, { letter: 'B', text: '1.5 standard deviations above the mean' }, { letter: 'C', text: '1.5 times the mean' }, { letter: 'D', text: 'At the 15th percentile exactly' }], correct: 'A', explanation: 'A negative z-score indicates the value is below the mean by that many standard deviations.' },
  { id: 'sat_math_b10_078', category: 'math', subcategory: 'data-analysis', difficulty: 'medium', passage: null, question: 'A dot plot shows the following values: 2, 2, 3, 3, 3, 4, 5, 5, 8. Which measure of center is most affected by the outlier 8?', options: [{ letter: 'A', text: 'Mean' }, { letter: 'B', text: 'Median' }, { letter: 'C', text: 'Mode' }, { letter: 'D', text: 'All are equally affected' }], correct: 'A', explanation: 'The mean is most sensitive to extreme values because it uses every data point in its calculation.' },
  { id: 'sat_math_b10_079', category: 'math', subcategory: 'data-analysis', difficulty: 'medium', passage: null, question: 'A stratified sample is being taken from a school with 300 freshmen, 250 sophomores, 200 juniors, and 250 seniors. If 50 students total are sampled proportionally, how many freshmen should be selected?', options: [{ letter: 'A', text: '15' }, { letter: 'B', text: '12' }, { letter: 'C', text: '20' }, { letter: 'D', text: '10' }], correct: 'A', explanation: 'Total students = 1000. Freshmen proportion = 300/1000 = 0.3. Number sampled = 0.3 × 50 = 15.' },
  { id: 'sat_math_b10_080', category: 'math', subcategory: 'data-analysis', difficulty: 'medium', passage: null, question: 'A game involves rolling a die. You win $12 if you roll a 6 and lose $3 otherwise. What is the expected value per roll?', options: [{ letter: 'A', text: '-$0.50' }, { letter: 'B', text: '$0.50' }, { letter: 'C', text: '$1.50' }, { letter: 'D', text: '-$1.00' }], correct: 'A', explanation: 'E = (1/6)(12) + (5/6)(−3) = 2 − 2.50 = −$0.50.' },
  { id: 'sat_math_b10_081', category: 'math', subcategory: 'data-analysis', difficulty: 'medium', passage: null, question: 'In a normal distribution with mean 500 and standard deviation 100, what z-score corresponds to a value of 350?', options: [{ letter: 'A', text: '-1.5' }, { letter: 'B', text: '1.5' }, { letter: 'C', text: '-2.5' }, { letter: 'D', text: '-0.5' }], correct: 'A', explanation: 'z = (350 − 500) / 100 = −150 / 100 = −1.5.' },
  { id: 'sat_math_b10_082', category: 'math', subcategory: 'data-analysis', difficulty: 'medium', passage: null, question: 'A two-way frequency table shows: Males who prefer cats = 15, Males who prefer dogs = 35, Females who prefer cats = 25, Females who prefer dogs = 25. What is the conditional probability of preferring cats given that the person is female?', options: [{ letter: 'A', text: '1/2' }, { letter: 'B', text: '1/4' }, { letter: 'C', text: '3/8' }, { letter: 'D', text: '5/8' }], correct: 'A', explanation: 'Total females = 25 + 25 = 50. P(cats | female) = 25/50 = 1/2.' },
  { id: 'sat_math_b10_083', category: 'math', subcategory: 'data-analysis', difficulty: 'medium', passage: null, question: 'Data set A has a standard deviation of 3 and data set B has a standard deviation of 7. Which set has more variability?', options: [{ letter: 'A', text: 'Data set B' }, { letter: 'B', text: 'Data set A' }, { letter: 'C', text: 'They have the same variability' }, { letter: 'D', text: 'Cannot be determined' }], correct: 'A', explanation: 'A larger standard deviation indicates greater spread, so data set B has more variability.' },
  { id: 'sat_math_b10_084', category: 'math', subcategory: 'algebra', difficulty: 'medium', passage: null, question: 'A company recorded the number of defective items each day for 5 days: 3, 1, 4, 1, 6. What is the mean absolute deviation?', options: [{ letter: 'A', text: '1.6' }, { letter: 'B', text: '2.0' }, { letter: 'C', text: '3.0' }, { letter: 'D', text: '1.2' }], correct: 'A', explanation: 'Mean = 15/5 = 3. Deviations: |3−3| + |1−3| + |4−3| + |1−3| + |6−3| = 0+2+1+2+3 = 8. MAD = 8/5 = 1.6.' },
  { id: 'sat_math_b10_085', category: 'math', subcategory: 'data-analysis', difficulty: 'medium', passage: null, question: 'A contingency table shows that P(A) = 0.6 and P(B|A) = 0.25. What is P(A and B)?', options: [{ letter: 'A', text: '0.15' }, { letter: 'B', text: '0.85' }, { letter: 'C', text: '0.35' }, { letter: 'D', text: '0.42' }], correct: 'A', explanation: 'P(A and B) = P(B|A) × P(A) = 0.25 × 0.6 = 0.15.' },
  { id: 'sat_math_b10_086', category: 'math', subcategory: 'data-analysis', difficulty: 'medium', passage: null, question: 'Which of the following correlation coefficients indicates the weakest linear relationship?', options: [{ letter: 'A', text: '0.15' }, { letter: 'B', text: '-0.72' }, { letter: 'C', text: '0.88' }, { letter: 'D', text: '-0.95' }], correct: 'A', explanation: 'The strength of a linear relationship is determined by |r|. The value 0.15 has the smallest absolute value.' },
  { id: 'sat_math_b10_087', category: 'math', subcategory: 'data-analysis', difficulty: 'medium', passage: null, question: 'Removing an outlier from a data set will most likely:', options: [{ letter: 'A', text: 'Decrease the standard deviation' }, { letter: 'B', text: 'Increase the standard deviation' }, { letter: 'C', text: 'Not change the standard deviation' }, { letter: 'D', text: 'Double the standard deviation' }], correct: 'A', explanation: 'Removing an outlier reduces the spread of the data, which decreases the standard deviation.' },
  { id: 'sat_math_b10_088', category: 'math', subcategory: 'data-analysis', difficulty: 'medium', passage: null, question: 'A sample of 100 measurements has a mean of 25 and a margin of error of ±3 at a 95% confidence level. What is the 95% confidence interval?', options: [{ letter: 'A', text: '22 to 28' }, { letter: 'B', text: '20 to 30' }, { letter: 'C', text: '24 to 26' }, { letter: 'D', text: '19 to 31' }], correct: 'A', explanation: 'The confidence interval is 25 ± 3, giving 22 to 28.' },
  { id: 'sat_math_b10_089', category: 'math', subcategory: 'data-analysis', difficulty: 'medium', passage: null, question: 'A scatter plot shows data points clustered tightly around a decreasing line. Which r value is most likely?', options: [{ letter: 'A', text: '-0.95' }, { letter: 'B', text: '0.95' }, { letter: 'C', text: '-0.30' }, { letter: 'D', text: '0.05' }], correct: 'A', explanation: 'Tight clustering around a decreasing line indicates a strong negative correlation, so r ≈ −0.95.' },
  { id: 'sat_math_b10_090', category: 'math', subcategory: 'data-analysis', difficulty: 'medium', passage: null, question: 'In a relative frequency table, the relative frequencies must sum to what value?', options: [{ letter: 'A', text: '1' }, { letter: 'B', text: '100' }, { letter: 'C', text: 'It depends on the data' }, { letter: 'D', text: '0' }], correct: 'A', explanation: 'Relative frequencies represent proportions of the whole, so they always sum to 1 (or 100%).' },
  { id: 'sat_math_b10_091', category: 'math', subcategory: 'data-analysis', difficulty: 'hard', passage: null, question: 'A normally distributed data set has a mean of 80 and standard deviation of 6. What percentage of data falls between 68 and 92?', options: [{ letter: 'A', text: '95%' }, { letter: 'B', text: '68%' }, { letter: 'C', text: '99.7%' }, { letter: 'D', text: '47.5%' }], correct: 'A', explanation: '68 = 80 − 2(6) and 92 = 80 + 2(6). Within 2 standard deviations, approximately 95% of data falls.' },
  { id: 'sat_math_b10_092', category: 'math', subcategory: 'data-analysis', difficulty: 'hard', passage: null, question: 'A factory produces items with a defect rate of 2%. In a random sample of 150 items, what is the expected number of defective items?', options: [{ letter: 'A', text: '3' }, { letter: 'B', text: '2' }, { letter: 'C', text: '7.5' }, { letter: 'D', text: '30' }], correct: 'A', explanation: 'Expected value = n × p = 150 × 0.02 = 3.' },
  { id: 'sat_math_b10_093', category: 'math', subcategory: 'data-analysis', difficulty: 'hard', passage: null, question: 'A data set has a mean of 40, a median of 35, and a mode of 30. What is the shape of the distribution?', options: [{ letter: 'A', text: 'Skewed right (positively skewed)' }, { letter: 'B', text: 'Skewed left (negatively skewed)' }, { letter: 'C', text: 'Symmetric' }, { letter: 'D', text: 'Uniform' }], correct: 'A', explanation: 'When mean > median > mode, the distribution has a tail extending to the right, so it is positively skewed.' },
  { id: 'sat_math_b10_094', category: 'math', subcategory: 'data-analysis', difficulty: 'hard', passage: null, question: 'In how many ways can a president, vice president, and treasurer be selected from a group of 10 people?', options: [{ letter: 'A', text: '720' }, { letter: 'B', text: '120' }, { letter: 'C', text: '1000' }, { letter: 'D', text: '30' }], correct: 'A', explanation: 'This is a permutation: P(10,3) = 10 × 9 × 8 = 720.' },
  { id: 'sat_math_b10_095', category: 'math', subcategory: 'data-analysis', difficulty: 'hard', passage: null, question: 'A survey has a 95% confidence interval of (42%, 48%) for voter support. If the sample size is quadrupled, what happens to the margin of error?', options: [{ letter: 'A', text: 'It is halved.' }, { letter: 'B', text: 'It is doubled.' }, { letter: 'C', text: 'It stays the same.' }, { letter: 'D', text: 'It is quartered.' }], correct: 'A', explanation: 'Margin of error is proportional to 1/√n. Quadrupling n gives 1/√(4n) = 1/(2√n), halving the margin of error.' },
  { id: 'sat_math_b10_096', category: 'math', subcategory: 'data-analysis', difficulty: 'hard', passage: null, question: 'A bag contains 5 red, 4 blue, and 3 green balls. Two balls are drawn without replacement. What is the probability both are red?', options: [{ letter: 'A', text: '5/33' }, { letter: 'B', text: '25/144' }, { letter: 'C', text: '1/6' }, { letter: 'D', text: '10/66' }], correct: 'A', explanation: 'P(both red) = (5/12)(4/11) = 20/132 = 5/33.' },
  { id: 'sat_math_b10_097', category: 'math', subcategory: 'data-analysis', difficulty: 'hard', passage: null, question: 'The line of best fit for a data set has equation y = 0.8x + 12 with r² = 0.64. What percentage of the variation in y is explained by the model?', options: [{ letter: 'A', text: '64%' }, { letter: 'B', text: '80%' }, { letter: 'C', text: '36%' }, { letter: 'D', text: '12%' }], correct: 'A', explanation: 'r² represents the proportion of variation in y explained by the linear model, which is 0.64 or 64%.' },
  { id: 'sat_math_b10_098', category: 'math', subcategory: 'data-analysis', difficulty: 'hard', passage: null, question: 'A lottery requires choosing 5 numbers from 1 to 42. How many different combinations are possible?', options: [{ letter: 'A', text: '850,668' }, { letter: 'B', text: '120' }, { letter: 'C', text: '210' }, { letter: 'D', text: '31,752' }], correct: 'A', explanation: 'C(42,5) = 42!/(5!×37!) = (42×41×40×39×38)/(5×4×3×2×1) = 850,668.' },
  { id: 'sat_math_b10_099', category: 'math', subcategory: 'data-analysis', difficulty: 'hard', passage: null, question: 'Two events are independent. P(A) = 0.3 and P(A or B) = 0.58. What is P(B)?', options: [{ letter: 'A', text: '0.4' }, { letter: 'B', text: '0.28' }, { letter: 'C', text: '0.88' }, { letter: 'D', text: '0.12' }], correct: 'A', explanation: 'P(A or B) = P(A) + P(B) − P(A)P(B). So 0.58 = 0.3 + P(B) − 0.3P(B), giving 0.28 = 0.7P(B), so P(B) = 0.4.' },
  { id: 'sat_math_b10_100', category: 'math', subcategory: 'data-analysis', difficulty: 'hard', passage: null, question: 'A data set of 100 values has a mean of 50 and standard deviation of 10. Using Chebyshev\'s theorem, at least what fraction of data lies within 3 standard deviations of the mean?', options: [{ letter: 'A', text: '8/9' }, { letter: 'B', text: '3/4' }, { letter: 'C', text: '15/16' }, { letter: 'D', text: '24/25' }], correct: 'A', explanation: 'Chebyshev\'s theorem states at least 1 − 1/k² of data lies within k standard deviations. For k=3: 1 − 1/9 = 8/9.' },
  { id: 'sat_math_b10_101', category: 'math', subcategory: 'data-analysis', difficulty: 'hard', passage: null, question: 'A weighted die has P(1) = P(2) = P(3) = P(4) = P(5) = 1/8 and P(6) = 3/8. What is the expected value of a single roll?', options: [{ letter: 'A', text: '4.125' }, { letter: 'B', text: '3.5' }, { letter: 'C', text: '4.5' }, { letter: 'D', text: '3.75' }], correct: 'A', explanation: 'E = (1+2+3+4+5)(1/8) + 6(3/8) = 15/8 + 18/8 = 33/8 = 4.125.' },
  { id: 'sat_math_b10_102', category: 'math', subcategory: 'data-analysis', difficulty: 'hard', passage: null, question: 'In a two-way table of 200 people, 120 are adults and 80 are children. Of the adults, 90 prefer pizza and 30 prefer pasta. Of the children, 60 prefer pizza and 20 prefer pasta. What is the relative risk of preferring pizza for adults compared to children?', options: [{ letter: 'A', text: '1' }, { letter: 'B', text: '0.75' }, { letter: 'C', text: '1.5' }, { letter: 'D', text: '2' }], correct: 'A', explanation: 'P(pizza|adult) = 90/120 = 0.75. P(pizza|child) = 60/80 = 0.75. Relative risk = 0.75/0.75 = 1.' },
  { id: 'sat_math_b10_103', category: 'math', subcategory: 'data-analysis', difficulty: 'hard', passage: null, question: 'If X follows a normal distribution with mean 100 and standard deviation 10, what is P(X > 100)?', options: [{ letter: 'A', text: '0.5' }, { letter: 'B', text: '0.68' }, { letter: 'C', text: '0.95' }, { letter: 'D', text: '0.34' }], correct: 'A', explanation: 'In a normal distribution, the mean is at the center, so exactly 50% of values lie above the mean.' },
  { id: 'sat_math_b10_104', category: 'math', subcategory: 'data-analysis', difficulty: 'hard', passage: null, question: 'A company survey of 1,600 customers has a margin of error of ±2.5%. If the company surveys 6,400 customers instead, what is the new margin of error?', options: [{ letter: 'A', text: '±1.25%' }, { letter: 'B', text: '±0.625%' }, { letter: 'C', text: '±5%' }, { letter: 'D', text: '±2.5%' }], correct: 'A', explanation: 'Quadrupling the sample size halves the margin of error: 2.5% / 2 = 1.25%.' },
  { id: 'sat_math_b10_105', category: 'math', subcategory: 'data-analysis', difficulty: 'hard', passage: null, question: 'A teacher records quiz scores: {5, 7, 7, 8, 9, 10, 10, 10, 12, 15}. The teacher removes the score 15. Which measure changes the most?', options: [{ letter: 'A', text: 'Mean' }, { letter: 'B', text: 'Median' }, { letter: 'C', text: 'Mode' }, { letter: 'D', text: 'IQR' }], correct: 'A', explanation: 'The value 15 is the largest and affects the sum directly; removing it changes the mean significantly while the median, mode, and IQR change little or not at all.' },
  { id: 'sat_math_b10_106', category: 'math', subcategory: 'data-analysis', difficulty: 'hard', passage: null, question: 'A standard normal distribution has mean 0 and standard deviation 1. What is the z-score that separates the top 2.5% from the rest?', options: [{ letter: 'A', text: '1.96' }, { letter: 'B', text: '2.58' }, { letter: 'C', text: '1.64' }, { letter: 'D', text: '2.33' }], correct: 'A', explanation: 'The top 2.5% corresponds to a z-score of approximately 1.96 in the standard normal distribution.' },
  { id: 'sat_math_b10_107', category: 'math', subcategory: 'data-analysis', difficulty: 'hard', passage: null, question: 'Three cards are drawn without replacement from a standard deck of 52. What is the probability that all three are hearts?', options: [{ letter: 'A', text: '11/850' }, { letter: 'B', text: '1/64' }, { letter: 'C', text: '3/52' }, { letter: 'D', text: '1/4' }], correct: 'A', explanation: 'P = (13/52)(12/51)(11/50) = 1716/132600 = 11/850.' },
  { id: 'sat_math_b10_108', category: 'math', subcategory: 'data-analysis', difficulty: 'hard', passage: null, question: 'A regression analysis yields residuals of −2, 1, 3, −1, and −1. What is the sum of the residuals?', options: [{ letter: 'A', text: '0' }, { letter: 'B', text: '8' }, { letter: 'C', text: '−2' }, { letter: 'D', text: '2' }], correct: 'A', explanation: 'Sum = −2 + 1 + 3 + (−1) + (−1) = 0. For a least-squares regression, the residuals always sum to 0.' },
  { id: 'sat_math_b10_109', category: 'math', subcategory: 'data-analysis', difficulty: 'hard', passage: null, question: 'A spinner has sections worth $1, $5, and $10 with probabilities 0.5, 0.3, and 0.2 respectively. What is the expected value per spin?', options: [{ letter: 'A', text: '$4.00' }, { letter: 'B', text: '$5.33' }, { letter: 'C', text: '$3.50' }, { letter: 'D', text: '$5.00' }], correct: 'A', explanation: 'E = 1(0.5) + 5(0.3) + 10(0.2) = 0.50 + 1.50 + 2.00 = $4.00.' },
  { id: 'sat_math_b10_110', category: 'math', subcategory: 'data-analysis', difficulty: 'hard', passage: null, question: 'In a study, the 90th percentile score is 142 and the 10th percentile score is 98. What is the interdecile range?', options: [{ letter: 'A', text: '44' }, { letter: 'B', text: '120' }, { letter: 'C', text: '22' }, { letter: 'D', text: '240' }], correct: 'A', explanation: 'The interdecile range is the difference between the 90th and 10th percentiles: 142 − 98 = 44.' },
  { id: 'sat_math_b10_111', category: 'math', subcategory: 'data-analysis', difficulty: 'hard', passage: null, question: 'A poll of 900 people reports that 54% support a policy with a margin of error of ±3.3%. Which statement is most accurate?', options: [{ letter: 'A', text: 'We are 95% confident that between 50.7% and 57.3% of the population supports the policy.' }, { letter: 'B', text: 'Exactly 54% of the population supports the policy.' }, { letter: 'C', text: 'The poll is unreliable because the margin of error is too large.' }, { letter: 'D', text: '54% of all polls would get this result.' }], correct: 'A', explanation: 'A margin of error gives a confidence interval: 54% ± 3.3% = 50.7% to 57.3%.' },
  { id: 'sat_math_b10_112', category: 'math', subcategory: 'data-analysis', difficulty: 'hard', passage: null, question: 'If events A and B are not independent, P(A) = 0.5, P(B) = 0.4, and P(A and B) = 0.3, what is P(A|B)?', options: [{ letter: 'A', text: '0.75' }, { letter: 'B', text: '0.60' }, { letter: 'C', text: '0.50' }, { letter: 'D', text: '0.30' }], correct: 'A', explanation: 'P(A|B) = P(A and B) / P(B) = 0.3 / 0.4 = 0.75.' },
  { id: 'sat_math_b10_113', category: 'math', subcategory: 'algebra', difficulty: 'hard', passage: null, question: 'The average of 5 numbers is 14. When a sixth number is added, the average becomes 16. What is the sixth number?', options: [{ letter: 'A', text: '26' }, { letter: 'B', text: '24' }, { letter: 'C', text: '16' }, { letter: 'D', text: '30' }], correct: 'A', explanation: 'Original sum = 5 × 14 = 70. New sum = 6 × 16 = 96. Sixth number = 96 − 70 = 26.' },
  { id: 'sat_math_b10_114', category: 'math', subcategory: 'data-analysis', difficulty: 'hard', passage: null, question: 'A sample has a standard deviation of 4. If every value in the sample is multiplied by 3, what is the new standard deviation?', options: [{ letter: 'A', text: '12' }, { letter: 'B', text: '4' }, { letter: 'C', text: '7' }, { letter: 'D', text: '16' }], correct: 'A', explanation: 'Multiplying all values by a constant c multiplies the standard deviation by |c|: 4 × 3 = 12.' },
  { id: 'sat_math_b10_115', category: 'math', subcategory: 'data-analysis', difficulty: 'hard', passage: null, question: 'A researcher collects data from a voluntary response survey posted online. What is the biggest concern about this sampling method?', options: [{ letter: 'A', text: 'Response bias, because people with strong opinions are more likely to respond.' }, { letter: 'B', text: 'The sample size may be too large.' }, { letter: 'C', text: 'It is too expensive.' }, { letter: 'D', text: 'It uses too many variables.' }], correct: 'A', explanation: 'Voluntary response surveys tend to attract respondents with strong opinions, creating bias.' },
  { id: 'sat_math_b10_116', category: 'math', subcategory: 'data-analysis', difficulty: 'hard', passage: null, question: 'In a binomial experiment with n = 4 and p = 0.5, what is the probability of exactly 3 successes?', options: [{ letter: 'A', text: '1/4' }, { letter: 'B', text: '1/8' }, { letter: 'C', text: '3/8' }, { letter: 'D', text: '1/16' }], correct: 'A', explanation: 'P(X=3) = C(4,3)(0.5)³(0.5)¹ = 4 × 1/16 = 4/16 = 1/4.' },
  { id: 'sat_math_b10_117', category: 'math', subcategory: 'data-analysis', difficulty: 'hard', passage: null, question: 'A data set has the following percentiles: P25 = 40, P50 = 55, P75 = 70, P90 = 85. Approximately what percentage of data values are between 55 and 85?', options: [{ letter: 'A', text: '40%' }, { letter: 'B', text: '50%' }, { letter: 'C', text: '35%' }, { letter: 'D', text: '25%' }], correct: 'A', explanation: 'Between P50 and P90 lies 90% − 50% = 40% of the data.' },
  { id: 'sat_math_b10_118', category: 'math', subcategory: 'data-analysis', difficulty: 'hard', passage: null, question: 'A normal distribution has mean 200 and standard deviation 25. What is the probability that a value is between 175 and 225?', options: [{ letter: 'A', text: 'Approximately 68%' }, { letter: 'B', text: 'Approximately 95%' }, { letter: 'C', text: 'Approximately 50%' }, { letter: 'D', text: 'Approximately 99.7%' }], correct: 'A', explanation: '175 = 200 − 25 and 225 = 200 + 25, which is within 1 standard deviation. By the empirical rule, approximately 68% of data falls in this range.' },
  { id: 'sat_math_b10_119', category: 'math', subcategory: 'data-analysis', difficulty: 'hard', passage: null, question: 'A clinical trial tests a new drug on 200 patients. 120 receive the drug and 80 receive a placebo. Of those receiving the drug, 84 improved. Of those receiving the placebo, 40 improved. What is the difference in improvement rates?', options: [{ letter: 'A', text: '20 percentage points' }, { letter: 'B', text: '10 percentage points' }, { letter: 'C', text: '44 percentage points' }, { letter: 'D', text: '30 percentage points' }], correct: 'A', explanation: 'Drug rate = 84/120 = 70%. Placebo rate = 40/80 = 50%. Difference = 70% − 50% = 20 percentage points.' },
  { id: 'sat_math_b10_120', category: 'math', subcategory: 'data-analysis', difficulty: 'hard', passage: null, question: 'An experiment has two stages. Stage 1 has 3 outcomes, and for each outcome of Stage 1, Stage 2 has 4 outcomes. If one Stage 1 outcome is eliminated, how many total outcomes remain?', options: [{ letter: 'A', text: '8' }, { letter: 'B', text: '12' }, { letter: 'C', text: '7' }, { letter: 'D', text: '10' }], correct: 'A', explanation: 'After removing one Stage 1 outcome, 2 remain. Total outcomes = 2 × 4 = 8.' },
];
